const _ch=s=>{let x=0;for(let i=0;i<s.length;i++)x=(x*31+s.charCodeAt(i))>>>0;return (x%1000)/1000;};
const _mk=(oy,bv,vv,rm,rb)=>{const o={};Object.entries(RES).forEach(([ab,d])=>{o[ab]={y:+(d.y+oy+(_ch(ab+"y")-0.5)*0.5).toFixed(2),v:+Math.max(0.5,bv+(_ch(ab+"v")-0.5)*vv).toFixed(1),r:+Math.max(0,rb+d.r*rm+(_ch(ab+"r")-0.5)*0.4).toFixed(1)};});return o;};
const RE_SECTOR={residential:RES,office:_mk(0.6,5.0,5,0.5,0.3),logistics:_mk(1.6,4.0,4,0.4,0.5)};
