const GE_TAX={"Aire-la-Ville":51,"Anières":31,"Avully":51,"Avusy":50,"Bardonnex":45,"Bellevue":40,"Bernex":46,"Carouge (GE)":39,"Cartigny":45,"Chancy":51,"Choulex":36,"Chêne-Bougeries":34,"Chêne-Bourg":46,"Collex-Bossy":43,"Collonge-Bellerive":31,"Cologny":27,"Confignon":45,"Corsier (GE)":33,"Céligny":26,"Dardagny":46,"Genthod":25,"Genève":45.5,"Gy":34,"Hermance":38,"Jussy":43,"Laconnex":50,"Lancy":46,"Le Grand-Saconnex":44,"Meinier":41,"Meyrin":44,"Onex":50.5,"Perly-Certoux":44,"Plan-les-Ouates":42,"Pregny-Chambésy":31,"Presinge":42,"Puplinge":43,"Russin":48,"Satigny":46,"Soral":49,"Thônex":43,"Troinex":41,"Vandoeuvres":30,"Vernier":50,"Versoix":44,"Veyrier":38};
const _gh=s=>{let x=0;for(let i=0;i<s.length;i++)x=(x*31+s.charCodeAt(i))>>>0;return (x%1000)/1000;};
/* richer commune factors for opportunity scoring (representative; tax is real). dev/momentum tiers reflect Geneva grands projets / zones de developpement */
const DEV_HI=["Lancy","Carouge (GE)","Vernier","Onex","Plan-les-Ouates","Bernex","Le Grand-Saconnex","Meyrin","Genève","Confignon","Chêne-Bourg","Thônex","Perly-Certoux"];
const DEV_LO=["Cologny","Genthod","Vandoeuvres","Collonge-Bellerive","Anières","Pregny-Chambésy","Céligny","Choulex","Corsier (GE)","Hermance","Gy","Jussy","Presinge","Meinier","Bardonnex","Soral","Avully","Avusy","Cartigny","Laconnex","Russin","Dardagny","Aire-la-Ville","Chancy"];
const MOM_HI=["Lancy","Carouge (GE)","Genève","Bernex","Plan-les-Ouates","Le Grand-Saconnex","Vernier","Meyrin","Confignon","Chêne-Bourg","Thônex"];
const MOM_LO=["Céligny","Gy","Presinge","Jussy","Russin","Dardagny","Soral","Avusy","Chancy","Laconnex","Hermance","Choulex","Avully"];
const tier=(n,hi,lo)=>hi.includes(n)?0.85:lo.includes(n)?0.2:0.5;
const GE_FACT={}; Object.entries(GE_TAX).forEach(([n,tax])=>{const prime=Math.max(0,Math.min(1,(51-tax)/(51-25)));GE_FACT[n]={tax,y:+(2.2+(1-prime)*1.4+(_gh(n+"y")-0.5)*0.7).toFixed(2),vac:+Math.max(0.2,0.35+(1-prime)*1.15+(_gh(n+"v")-0.5)*0.7).toFixed(2),price:Math.round(8000+prime*8500+(_gh(n+"p")-0.5)*3500),dev:tier(n,DEV_HI,DEV_LO),mom:tier(n,MOM_HI,MOM_LO)};});
const GE_COM={}; Object.keys(GE_FACT).forEach(n=>{const f=GE_FACT[n];GE_COM[n]={tax:f.tax,y:f.y,vac:f.vac};});
/* commune-level office & logistics: representative, masked to communes that actually carry that stock (industrial zones / business districts) */
const OFF_C=["Genève","Lancy","Carouge (GE)","Meyrin","Plan-les-Ouates","Le Grand-Saconnex","Vernier","Chêne-Bourg","Thônex","Onex","Bernex","Versoix"];
const LOG_C=["Meyrin","Satigny","Vernier","Plan-les-Ouates","Lancy","Carouge (GE)","Onex","Le Grand-Saconnex","Confignon","Bernex","Genève"];
const _geSec=(core,oy,bv,vv,pmul)=>{const o={};Object.keys(GE_TAX).forEach(n=>{const f=GE_FACT[n];const isC=core.includes(n);o[n]={tax:f.tax,y:+(f.y+oy+(isC?0:0.15)+(_gh(n+"sy")-0.5)*0.5).toFixed(2),vac:+Math.max(1.0,bv+(isC?-1.0:0.8)+(_gh(n+"sv")-0.5)*vv).toFixed(2),price:Math.round(f.price*pmul),dev:f.dev,mom:f.mom,core:isC};});return o;};
const GE_SECT={residential:GE_FACT,office:_geSec(OFF_C,0.6,4.8,3.0,0.95),logistics:_geSec(LOG_C,1.5,3.5,3.0,0.55)};
const WKEYS=["y","vac","tax","dev","price","mom"];
const WLAB={y:"Yield",vac:"Security",tax:"Tax eff.",dev:"Dev. potential",price:"Entry price",mom:"Momentum"};
const FBS={};Object.keys(GE_SECT).forEach(sec=>{const F=GE_SECT[sec],fb={};WKEYS.forEach(k=>{const a=Object.values(F).map(f=>f[k]);fb[k]=[Math.min(...a),Math.max(...a)];});FBS[sec]=fb;});
const fnorm=(sec,k,v)=>{const[a,b]=FBS[sec][k];const t=b===a?0.5:(v-a)/(b-a);return (k==="vac"||k==="tax"||k==="price")?1-t:t;};
function scoreFor(name,w,sec){sec=sec||"residential";const F=GE_SECT[sec]||GE_FACT;const f=F[name];if(!f)return null;let s=0,tot=0;WKEYS.forEach(k=>{s+=(w[k]||0)*fnorm(sec,k,f[k]);tot+=(w[k]||0);});return tot?+((s/tot)*100).toFixed(1):0;}
function drivers(name,w,sec){sec=sec||"residential";const F=GE_SECT[sec]||GE_FACT;const f=F[name];if(!f)return[];return WKEYS.map(k=>({k,c:(w[k]||0)*fnorm(sec,k,f[k])})).sort((a,b)=>b.c-a.c).slice(0,2).map(d=>WLAB[d.k]);}
